(function () {
  var nativeSetter = Object.getOwnPropertyDescriptor(
    window.HTMLInputElement.prototype, 'value'
  ).set;

  function rellenarYocultar() {
    var c = document.getElementById('city');
    var m = document.getElementById('municipality');
    if (!c || !m) return;

    var texto = m.textContent.trim();
    if (texto && texto !== 'Seleccione...') {
      if (c.value !== texto) {
        nativeSetter.call(c, texto);
        c.dispatchEvent(new Event('input', { bubbles: true }));
        c.dispatchEvent(new Event('change', { bubbles: true }));
      }
    }

    var bloque = c.closest('.form-group');
    if (bloque && bloque.style.display !== 'none') {
      bloque.style.display = 'none';
    }
  }

  function rafaga() {
    rellenarYocultar();
    var t = 0;
    var iv = setInterval(function () {
      rellenarYocultar();
      t += 150;
      if (t >= 1500) clearInterval(iv);
    }, 150);
  }

  var pendiente;
  function programar() {
    if (pendiente) return;
    pendiente = setTimeout(function () { pendiente = null; rafaga(); }, 50);
  }

  var obs = new MutationObserver(programar);
  obs.observe(document.body, { childList: true, subtree: true });
  rafaga();
})();
